															curr_item_tax_type = curr_monthly_rental.Tax_Type_Monthly_Rental;
															curr_item_tax_percentage = curr_monthly_rental.Tax_Pct_Monthly_Rental;
															curr_item_tax_amount = curr_monthly_rental.Tax_Amount_Monthly_Rental;
															curr_item = {"item_name":curr_item_name,"item_classification_code_list":curr_item_classification_code_list,"item_description":curr_item_description,"item_quantity":curr_item_quantity,"item_unit_price":curr_item_unit_price,"item_price_extension":curr_item_price_extension,"item_tax_type":curr_item_tax_type,"item_tax_percentage":curr_item_tax_percentage,"item_tax_amount":curr_item_tax_amount};
															line_item_list.add(curr_item);
														}
														for each  curr_internet_charge in input.Internet_Charges
														{
															curr_item_name = curr_internet_charge.Item_Code_Internet_Charges;
															curr_item_classification_code_list = curr_internet_charge.Classification_Codes_Internet_Charges;
															curr_item_description = "Internet Charge: " + curr_internet_charge.Description_Internet_Charges;
															curr_item_quantity = curr_internet_charge.Quantity_Internet_Charges;
															curr_item_unit_price = curr_internet_charge.Unit_Price_Internet_Charges;
															curr_item_price_extension = curr_internet_charge.Sub_Total_Internet_Charges;
															curr_item_tax_type = curr_internet_charge.Tax_Type_Internet_Charges;
															curr_item_tax_percentage = curr_internet_charge.Tax_Pct_Internet_Charges;
															curr_item_tax_amount = curr_internet_charge.Tax_Amount_Internet_Charges;
															curr_item = {"item_name":curr_item_name,"item_classification_code_list":curr_item_classification_code_list,"item_description":curr_item_description,"item_quantity":curr_item_quantity,"item_unit_price":curr_item_unit_price,"item_price_extension":curr_item_price_extension,"item_tax_type":curr_item_tax_type,"item_tax_percentage":curr_item_tax_percentage,"item_tax_amount":curr_item_tax_amount};
															line_item_list.add(curr_item);
														}
														for each  curr_call_charge in input.Call_Charges
														{
															curr_item_name = curr_call_charge.Item_Code_Call_Charges;
															curr_item_classification_code_list = curr_call_charge.Classification_Codes_Call_Charges;
