															curr_item_tax_type = curr_call_charge.Tax_Type_Call_Charges;
															curr_item_tax_percentage = curr_call_charge.Tax_Pct_Call_Charges;
															curr_item_tax_amount = curr_call_charge.Tax_Amount_Call_Charges;
															curr_item = {"item_name":curr_item_name,"item_classification_code_list":curr_item_classification_code_list,"item_description":curr_item_description,"item_quantity":curr_item_quantity,"item_unit_price":curr_item_unit_price,"item_price_extension":curr_item_price_extension,"item_tax_type":curr_item_tax_type,"item_tax_percentage":curr_item_tax_percentage,"item_tax_amount":curr_item_tax_amount};
															line_item_list.add(curr_item);
														}
														invoice_get_response = Map();
														invoice_get_response.put("Invoice_Date",input.Invoice_Date);
														invoice_get_response.put("Invoice_No",input.Invoice_No);
														invoice_get_response.put("Payment_Term",input.Payment_Term.Days.toString());
														invoice_get_response.put("ID",input.ID);
														invoice_get_response.put("Due_Date",input.Due_Date);
														invoice_get_response.put("invoice_uuid",input.Invoice_UUID);
														invoice_get_response.put("invoice_public_link",input.Invoice_Public_Link);
