														invoice_submit_lhdn_output = thisapp.invoice_submit_lhdn(invoice,organization,customer);
														info invoice_submit_lhdn_output.get("output").toMap();
														invoice_submit_lhdn_output = invoice_submit_lhdn_output.get("output").toMap();
														current_date_time = zoho.currenttime;
														new_row_invoice_related_list = Invoice.Invoice_Related_List();
														new_row_invoice_related_list.USERNAME=zoho_loginuser;
														new_row_invoice_related_list.INVOICE_NUMBER=input.Invoice_No;
														new_row_invoice_related_list.Related_List_Date=current_date_time.toDate();
														new_row_invoice_related_list.Related_List_Time=current_date_time.toTime();
														new_row_invoice_related_list.SUBMISSION_ID=invoice_submit_lhdn_output.get("SUBMISSION_ID");
														new_row_invoice_related_list.UUID=invoice_submit_lhdn_output.get("UUID_LINK");
